+function findBalancedClosingParenthesis(text: string, start: number): number | null {
+  let depth = 1;
+  for (let index = start + 1; index < text.length; index++) {
+    if (text[index] === '\\\') {
+      index++;
+    } else if (text[index] === '(') {
+      depth++;
+    } else if (text[index] === ')') {
